(function(){const canvas=document.getElementById('nebula-canvas');if(!canvas)return;const ctx=canvas.getContext('2d',{alpha:false});let width,height,stars=[],fireflies=[];let mouseX=0,mouseY=0;let scrollY=0,maxScroll=0;const STAR_COUNT=350,FIREFLY_COUNT=45,SPEED=0.05;function resize(){width=window.innerWidth;height=window.innerHeight;canvas.width=width;canvas.height=height;maxScroll=document.documentElement.scrollHeight-window.innerHeight;initStars();initFireflies()}function initStars(){stars=[];for(let i=0;i<STAR_COUNT;i++){stars.push({x:Math.random()*width,y:Math.random()*height,z:Math.random()*width,radius:Math.random()*1.5+0.5,alpha:Math.random()*0.8+0.2,blinkSpeed:(Math.random()*0.02)+0.005,blinkDir:Math.random()>0.5?1:-1})}}function initFireflies(){fireflies=[];for(let i=0;i<FIREFLY_COUNT;i++){fireflies.push({x:Math.random()*width,y:Math.random()*height,radius:Math.random()*1.8+0.8,alpha:Math.random()*0.4+0.2,speed:Math.random()*0.45+0.225,angle:Math.random()*Math.PI*2,drift:(Math.random()*0.02+0.01)*0.75,oscillation:Math.random()*30+10})}}const nebulas=[{x:0.1,y:0.2,r:0.7,color:'rgba(255,0,60,0.08)',vx:0.0001,vy:0.00015},{x:0.9,y:0.8,r:0.6,color:'rgba(0,229,255,0.08)',vx:-0.00015,vy:0.0001},{x:0.5,y:0.5,r:0.8,color:'rgba(0,0,50,0.05)',vx:0.0001,vy:-0.0001}];function drawNebulas(){for(let n of nebulas){n.x+=n.vx;n.y+=n.vy;if(n.x<-0.2||n.x>1.2)n.vx*=-1;if(n.y<-0.2||n.y>1.2)n.vy*=-1;const offsetX=mouseX*20,offsetY=mouseY*20;const px=n.x*width+offsetX,py=n.y*height+offsetY,pr=n.r*Math.max(width,height);const g=ctx.createRadialGradient(px,py,0,px,py,pr);g.addColorStop(0,n.color);g.addColorStop(1,'rgba(0,0,0,0)');ctx.fillStyle=g;ctx.globalCompositeOperation='screen';ctx.fillRect(0,0,width,height);ctx.globalCompositeOperation='source-over'}}function drawScrollHaze(){const p=maxScroll>0?scrollY/maxScroll:0;const cA=Math.max(0,0.1*(1-p));if(cA>0){const gL=ctx.createRadialGradient(0,height,0,0,height,width*0.15);gL.addColorStop(0,`rgba(255,0,60,${cA})`);gL.addColorStop(1,'rgba(0,0,0,0)');const gR=ctx.createRadialGradient(width,height,0,width,height,width*0.15);gR.addColorStop(0,`rgba(255,0,60,${cA})`);gR.addColorStop(1,'rgba(0,0,0,0)');ctx.globalCompositeOperation='screen';ctx.fillStyle=gL;ctx.fillRect(0,0,width,height);ctx.fillStyle=gR;ctx.fillRect(0,0,width,height)}const cerA=Math.max(0,0.8*p);if(cerA>0){const gC=ctx.createRadialGradient(width/2,height,0,width/2,height,height*2);gC.addColorStop(0,`rgba(0,229,255,${cerA})`);gC.addColorStop(1,'rgba(0,0,0,0)');ctx.globalCompositeOperation='screen';ctx.fillStyle=gC;ctx.fillRect(0,0,width,height)}ctx.globalCompositeOperation='source-over'}function drawStars(){ctx.fillStyle='rgba(3,0,8,1)';ctx.fillRect(0,0,width,height);drawNebulas();drawScrollHaze();for(let s of stars){const speed=(width-s.z)*SPEED*0.001;s.y-=speed;s.alpha+=s.blinkSpeed*s.blinkDir;if(s.alpha>=1){s.alpha=1;s.blinkDir=-1}else if(s.alpha<=0.1){s.alpha=0.1;s.blinkDir=1}if(s.y<0){s.y=height;s.x=Math.random()*width;s.z=Math.random()*width}const scale=(width-s.z)/width,r=s.radius*scale,a=s.alpha*scale;const pX=mouseX*(1-scale)*40,pY=mouseY*(1-scale)*40;ctx.beginPath();ctx.fillStyle=`rgba(226,232,240,${a})`;ctx.arc(s.x+pX,s.y+pY,r,0,Math.PI*2);ctx.fill()}}function drawFireflies(){for(let f of fireflies){f.y-=f.speed;f.angle+=f.drift;const oX=Math.sin(f.angle)*f.oscillation;const cA=f.alpha+(Math.sin(f.angle*2)*0.1);if(f.y<-50){f.y=height+50;f.x=Math.random()*width}const pX=mouseX*50,pY=mouseY*50;ctx.beginPath();ctx.fillStyle=`rgba(0,229,255,${Math.max(0.1,cA)})`;ctx.arc(f.x+oX+pX,f.y+pY,f.radius,0,Math.PI*2);ctx.fill()}}let animId;function animate(){drawStars();drawFireflies();animId=requestAnimationFrame(animate)}window.addEventListener('resize',()=>{cancelAnimationFrame(animId);resize();animate()});window.addEventListener('mousemove',(e)=>{mouseX=(e.clientX/window.innerWidth)-0.5;mouseY=(e.clientY/window.innerHeight)-0.5});window.addEventListener('scroll',()=>{scrollY=window.scrollY},{passive:true});resize();animate()})();

document.addEventListener('DOMContentLoaded',()=>{const fadeUpElements=document.querySelectorAll('.fade-up');const observer=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if(entry.isIntersecting){entry.target.classList.add('visible');observer.unobserve(entry.target)}})},{root:null,rootMargin:'0px 0px -10% 0px',threshold:0.1});fadeUpElements.forEach(el=>observer.observe(el));const navToggle=document.querySelector('.mobile-menu-toggle'),navLinks=document.querySelector('.nav-links');if(navToggle&&navLinks){navToggle.addEventListener('click',()=>{if(navLinks.style.display==='flex'){navLinks.style.display='none'}else{navLinks.style.display='flex';navLinks.style.flexDirection='column';navLinks.style.position='absolute';navLinks.style.top='100%';navLinks.style.left='0';navLinks.style.width='100%';navLinks.style.backgroundColor='rgba(3,0,8,0.95)';navLinks.style.padding='1rem';navLinks.style.borderBottom='1px solid rgba(0,229,255,0.2)'}})}navLinks.querySelectorAll('a').forEach(link=>{link.addEventListener('click',()=>{if(window.innerWidth<=768){navLinks.style.display='none'}})});window.addEventListener('resize',()=>{if(window.innerWidth>768&&navLinks.style.display==='none'){navLinks.style.display='';navLinks.style.flexDirection='';navLinks.style.position='';navLinks.style.backgroundColor='';navLinks.style.padding='';navLinks.style.borderBottom=''}});document.querySelectorAll('a[href^="#"]').forEach(anchor=>{anchor.addEventListener('click',function(e){e.preventDefault();const targetId=this.getAttribute('href');if(targetId==='#')return;const targetElement=document.querySelector(targetId);if(targetElement){const headerOffset=80,elementPosition=targetElement.getBoundingClientRect().top,offsetPosition=elementPosition+window.pageYOffset-headerOffset;window.scrollTo({top:offsetPosition,behavior:'smooth'})}})})});

(function(){const container=document.getElementById('medium-latest');if(!container)return;const profileUrl='https://medium.com/@mikewyantjr',feedUrl='https://medium.com/feed/@mikewyantjr',apiUrl='https://api.rss2json.com/v1/api.json?rss_url='+encodeURIComponent(feedUrl);function createFallback(){container.innerHTML='<p><a href="'+profileUrl+'" target="_blank" rel="noopener">Read more posts on Medium</a></p>'}function stripHtml(html){const tmp=document.createElement('div');tmp.innerHTML=html;return tmp.textContent||tmp.innerText||''}fetch(apiUrl).then(r=>{if(!r.ok)throw new Error();return r.json()}).then(data=>{if(!data||!Array.isArray(data.items)||!data.items.length){createFallback();return}const item=data.items[0],title=item.title||'Latest post on Medium',link=item.link||profileUrl,pubDate=item.pubDate?new Date(item.pubDate):null,description=stripHtml(item.description||'').slice(0,260).trim(),formattedDate=pubDate?pubDate.toLocaleDateString(undefined,{year:'numeric',month:'short',day:'numeric'}):'';var html='';if(formattedDate){html+='<div class="medium-meta">'+formattedDate+'</div>'}html+='<h3 class="medium-title"><a href="'+link+'" target="_blank" rel="noopener">'+title+'</a></h3>';if(description){html+='<p class="medium-excerpt">'+description+(description.length===260?'…':'')+'</p>'}html+='<p><a class="button w-button" href="'+link+'" target="_blank" rel="noopener">Read on Medium</a></p>';container.innerHTML=html}).catch(()=>{createFallback()})})();
